const items = $input.all();

return items.map(item => {
  return {
    json: {
      logContent: item.json.data,
      source: 'github',
      fetchedAt: new Date().toISOString()
    }
  };
});

const items = $input.all();
const results = [];

items.forEach(item => {
  const lines = item.json.logContent.split('\n');

  lines.forEach((line, index) => {
    if (line.trim()) {
      results.push({
        json: {
          lineNumber: index + 1,
          logLine: line.trim(),
          ingestedAt: item.json.fetchedAt
        }
      });
    }
  });
});

return results;

// Parse both Web (Apache/Nginx) and System (SSH/Auth) log formats
const items = $input.all();

return items.map(item => {
  const line = item.json.logLine;

  // 1. Apache/Nginx combined log regex
  const apacheRegex = /^(\S+) \S+ \S+ \[([^\]]+)\] "(\S+) ([^"]*) HTTP\/[^"]+" (\d+) (\d+|-) "([^"]*)" "([^"]*)"/;

  // 2. Linux Auth/SSH regex (e.g., Failed password for root from 192.168.1.100)
  const authRegex = /([A-Z][a-z]{2}\s+\d+\s\d{2}:\d{2}:\d{2}).*?(\b\d{1,3}(?:\.\d{1,3}){3}\b)/;

  const apacheMatch = line.match(apacheRegex);
  const authMatch = line.match(authRegex);

  if (apacheMatch) {
    return {
      json: {
        lineNumber: item.json.lineNumber,
        logType: 'WEB',
        ip: apacheMatch[1],
        timestamp: apacheMatch[2],
        method: apacheMatch[3],
        path: apacheMatch[4],
        statusCode: parseInt(apacheMatch[5]),
        userAgent: apacheMatch[8],
        rawLine: line
      }
    };
  } else if (authMatch) {
    return {
      json: {
        lineNumber: item.json.lineNumber,
        logType: 'SSH',
        timestamp: authMatch[1],
        ip: authMatch[2],
        path: 'SSH Login Attempt', // Filler for the threat detector
        method: 'AUTH',
        statusCode: line.toLowerCase().includes('failed') ? 401 : 200,
        userAgent: 'Internal System Process',
        rawLine: line
      }
    };
  }

  return {
    json: {
      ...item.json,
      parseError: true,
      rawLine: line
    }
  };
});

// Detect security threats using pattern matching
const items = $input.all();

// Threat detection patterns
const threatPatterns = [
  {
    name: 'SQL Injection',
    regex: /(union\s+select|or\s+1\s*=\s*1|drop\s+table|insert\s+into|';\s*--)/i,
    severity: 'CRITICAL',
    score: 30
  },
  {
    name: 'Path Traversal',
    regex: /(\.\.\/|\.\.%2f|\.\.%5c|\.\.\\|\.\.\/\.\.\/|\.\.%252f)/i,
    severity: 'HIGH',
    score: 25
  },
  {
    name: 'XSS Attempt',
    regex: /(<script|javascript:|onerror=|onload=|<img|alert\(|eval\()/i,
    severity: 'HIGH',
    score: 20
  },
  {
    name: 'Admin Panel Probing',
    regex: /\/(admin|administrator|wp-admin|phpmyadmin|adminer|manager)/i,
    severity: 'MEDIUM',
    score: 10
  },
  {
    name: 'Scanner Activity',
    regex: /(\/config\.php|\/\.env|\/backup\.sql|\/database\.sql|\/phpinfo\.php)/i,
    severity: 'MEDIUM',
    score: 15
  },
  {
    name: 'Shell Upload Attempt',
    regex: /(cmd\.php|shell\.asp|backdoor\.jsp|webshell|c99\.php|r57\.php)/i,
    severity: 'CRITICAL',
    score: 35
  },
  {
    name: 'Authentication Failure',
    regex: /(failed password|invalid user|authentication failure)/i,
    severity: 'MEDIUM',
    score: 10
  }
];

return items.map(item => {
  const path = item.json.path || '';
  const userAgent = item.json.userAgent || '';
  const statusCode = item.json.statusCode || 200;
  const detectedThreats = [];
  let threatScore = 0;

  // Check each pattern
  threatPatterns.forEach(pattern => {
    if (pattern.regex.test(path) || pattern.regex.test(userAgent)) {
      detectedThreats.push(pattern.name);
      threatScore += pattern.score;
    }
  });

  // Additional scoring based on status codes
  if (statusCode === 403 || statusCode === 401) {
    threatScore += 5;  // Blocked requests indicate malicious intent
  }

  // Check for scanner user agents
  const scannerAgents = ['nikto', 'nmap', 'sqlmap', 'burp', 'acunetix', 'nessus'];
  if (scannerAgents.some(scanner => userAgent.toLowerCase().includes(scanner))) {
    detectedThreats.push('Scanner User-Agent');
    threatScore += 15;
  }

  return {
    json: {
      ...item.json,
      threatsDetected: detectedThreats,
      threatCount: detectedThreats.length,
      threatScore: Math.min(threatScore, 100),  // Cap at 100
      isThreat: detectedThreats.length > 0
    }
  };
});

const items = $input.all();
const ipMap = {};

items.forEach(item => {
  const ip = item.json.ip;
  if (!ip) return;

  if (!ipMap[ip]) {
    ipMap[ip] = {
      ip,
      behaviors: new Set(),
      threatNames: new Set(), // Keeps the specific names for your GitHub tickets
      requestCount: 0,
      firstSeen: item.json.timestamp,
      lastSeen: item.json.timestamp
    };
  }

  const entry = ipMap[ip];
  entry.requestCount++;
  entry.lastSeen = item.json.timestamp;

  const threats = item.json.threatsDetected || [];

  threats.forEach(t => {
    entry.threatNames.add(t); // Maintains the list for the GitHub "Patterns" field

    // Categorize specific threats into behavioral stages
    if (t.includes('Scanner') || t.includes('404')) entry.behaviors.add('recon');
    if (t.includes('Admin')) entry.behaviors.add('discovery');
    if (t.includes('Authentication')) entry.behaviors.add('bruteforce');
    if (t.includes('SQL') || t.includes('XSS')) entry.behaviors.add('exploit');
    if (t.includes('Shell')) entry.behaviors.add('compromise');
  });
});

function calculateScore(entry) {
  let score = 0;

  // Behavior Weights
  if (entry.behaviors.has('recon')) score += 10;
  if (entry.behaviors.has('discovery')) score += 15;
  if (entry.behaviors.has('bruteforce')) score += 20;
  if (entry.behaviors.has('exploit')) score += 40;
  if (entry.behaviors.has('compromise')) score += 60;

  // Velocity scoring (Automation detection)
  if (entry.requestCount > 200) score += 25;

  // Multi-stage attack bonus (The "Intent" bonus)
  if (entry.behaviors.size >= 3) score += 20;

  return Math.min(score, 100);
}

const results = Object.values(ipMap).map(entry => {
  const finalScore = calculateScore(entry);

  let risk = 'LOW';
  if (finalScore >= 80) risk = 'CRITICAL';
  else if (finalScore >= 50) risk = 'HIGH';
  else if (finalScore >= 25) risk = 'MEDIUM';

  return {
    json: {
      ip: entry.ip,
      requestCount: entry.requestCount,
      // We keep 'threatTypes' so your downstream nodes don't turn red
      threatTypes: Array.from(entry.threatNames).join(', '),
      behaviorPatterns: Array.from(entry.behaviors).join(', '),
      finalThreatScore: finalScore,
      riskLevel: risk,
      firstSeen: entry.firstSeen,
      lastSeen: entry.lastSeen
    }
  };
});

// Sort by highest score
return results.sort((a, b) => b.json.finalThreatScore - a.json.finalThreatScore);

const items = $input.all();

/* ------------------------
   Aggregations
------------------------- */
const totalIPs = items.length;
const totalRequests = items.reduce((s, i) => s + (i.json.requestCount || 0), 0);
// We use finalThreatScore as a proxy for threat activity in the new behavioral model
const totalHighRiskEvents = items.filter(i => i.json.finalThreatScore > 25).length;

const riskCounts = { CRITICAL: 0, HIGH: 0, MEDIUM: 0, LOW: 0 };
const actionCounts = { BLOCK: 0, INVESTIGATE: 0, MONITOR: 0 };

items.forEach(i => {
  const level = i.json.riskLevel;
  if (riskCounts[level] !== undefined) riskCounts[level]++;

  const action = i.json.socAction;
  if (actionCounts[action] !== undefined) actionCounts[action]++;
});

const topThreatIPs = [...items]
  .sort((a, b) => (b.json.finalThreatScore || 0) - (a.json.finalThreatScore || 0))
  .slice(0, 10);

/* ------------------------
   Helper: Risk Distribution Bars
------------------------- */
const riskBar = (label, count, color) => {
  const percent = totalIPs ? Math.round((count / totalIPs) * 100) : 0;
  return `
  <div style="margin-bottom:12px;">
    <div style="display:flex; justify-content:between; font-size:13px; margin-bottom:4px;">
        <span><b>${label}</b></span>
        <span style="margin-left:auto;">${count} (${percent}%)</span>
    </div>
    <div style="background:#e5e7eb; height:12px; border-radius:6px; width:100%;">
      <div style="width:${percent}%; height:12px; background:${color}; border-radius:6px;"></div>
    </div>
  </div>`;
};

