return {
  json: {
    emailHtml: attachmentHtml,
    alertCount: riskCounts.CRITICAL + riskCounts.HIGH,
    summaryStats: { totalIPs, actionCounts, riskCounts }
  },
  binary: {
    report_file: {
      data: Buffer.from(attachmentHtml, 'utf8').toString('base64'),
      fileName: `SOC_Action_Report_${new Date().toISOString().split('T')[0]}.html`,
      mimeType: 'text/html'
    }
  }
};

const items = $input.all();

return items.map(item => {

  const abuse = item.json?.data || {};
  const score = abuse.abuseConfidenceScore ?? 0;
  const reports = abuse.totalReports ?? 0;
  const country = abuse.countryCode ?? "Unknown";

  let reputation = "UNKNOWN";
  if (score >= 80) reputation = "MALICIOUS";
  else if (score >= 30) reputation = "SUSPICIOUS";
  else reputation = "CLEAN";

  return {
    json: {
      ...item.json,
      reputationScore: score,
      reputationReports: reports,
      countryCode: country,
      reputation: reputation
    }
  };
});

const items = $input.all();
// Reach back to the Aggregate node to get the original scores and metadata
const aggregateNodeData = $("Aggregate Threats by IP").all();

return items.map(item => {
  const currentIp = item.json.ip || item.json.data?.ipAddress;

  // Find the matching IP data from the aggregate node
  const originalData = aggregateNodeData.find(a => a.json.ip === currentIp);

  // Pulling specific metadata to fix the "red" variable issues
  const score = originalData ? originalData.json.finalThreatScore : 0;
  const threatTypes = originalData ? originalData.json.threatTypes : "None Detected";
  const requestCount = originalData ? originalData.json.requestCount : 0;

  const rep = item.json.reputation || "UNKNOWN";

  let action = "IGNORE";
  let severity = "LOW";

  // Logic for Action and Severity
  if (score >= 40 && rep === "MALICIOUS") {
    action = "BLOCK";
    severity = "CRITICAL";
  } 
  else if (score >= 40 || rep === "MALICIOUS") {
    action = "INVESTIGATE";
    severity = "HIGH";
  }
  else if (score >= 20) {
    action = "MONITOR";
    severity = "MEDIUM";
  }

  return {
    json: {
      ...item.json,
      ip: currentIp,           // Ensures 'ip' is at the top level
      finalThreatScore: score, // Corrects the 0 score issue
      threatTypes: threatTypes, // Fixes the red variable in GitHub
      requestCount: requestCount, // Fixes the red variable in GitHub
      socAction: action,
      socSeverity: severity
    }
  };
});

// This simulates sending data to a Firewall (like Cloudflare, CrowdSec, or IPTables)
const items = $input.all();

const blocked = items.map(item => {
  return {
    json: {
      blockedIp: item.json.ip || item.json.data?.ipAddress,
      reason: `Automated SOC Block: ${item.json.socSeverity}`,
      threatScore: item.json.finalThreatScore,
      externalReputation: item.json.reputation,
      status: "SUCCESS",
      timestamp: new Date().toISOString(),
      firewallAction: "DROP"
    }
  };
});

// We wrap it this way so the output is a clean list of blocked actions
return blocked;

