// --- CONFIGURATION ---
const DEBUG_MODE = false;     // Set to true to bypass/clear cache
const CACHE_TTL_HOURS = 24;   // How long to remember an incident (24 hours)
// ---------------------

const staticData = $getWorkflowStaticData('global');

// 1. Handle Debug Mode
if (DEBUG_MODE) {
  staticData.processedIncidents = {}; 
  return $input.all(); 
}

staticData.processedIncidents = staticData.processedIncidents || {};
const now = Date.now();
const ttlMilliseconds = CACHE_TTL_HOURS * 60 * 60 * 1000;

return $input.all().filter(item => {
  const ip = item.json.ip;
  const action = item.json.socAction;
  const incidentKey = `${ip}-${action}`;

  // 2. Check if record exists and if it's still fresh
  if (staticData.processedIncidents[incidentKey]) {
    const lastSeen = new Date(staticData.processedIncidents[incidentKey]).getTime();

    if (now - lastSeen < ttlMilliseconds) {
      return false; // Still in "cooldown" - skip duplication
    }
  }

  // 3. Mark as seen (or refresh the timestamp)
  staticData.processedIncidents[incidentKey] = new Date().toISOString();
  return true;
});
